185→const SERVER_MESSAGES: Record<number, (param: string) => string> = {
186→  1: (p) => `Server shutdown in ${p}`,
187→  2: (p) => `Server restart in ${p}`,
188→  3: (p) => p,
189→  4: () => "Server shutdown cancelled",
