326→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
327→  const entries = parseUpdateObject(r);
328→  for (const entry of entries) {
329→    switch (entry.type) {
330→      case "create": {
331→        const { _changed: _co, ...objFields } = extractObjectFields(
332→          entry.fields,
333→        );
334→        let extraFields: Record<string, unknown> = {};
335→        if (
336→          entry.objectType === ObjectType.UNIT ||
337→          entry.objectType === ObjectType.PLAYER
338→        ) {
339→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
340→          extraFields = rest;
341→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
342→          const { _changed: _cg, ...rest } = extractGameObjectFields(
343→            entry.fields,
344→          );
345→          extraFields = rest;
346→        }
347→        const cachedName = lookupCachedName(
348→          conn,
349→          entry.guid,
350→          entry.objectType,
351→          objFields.entry,
352→        );
353→        conn.entityStore.create(entry.guid, entry.objectType, {
354→          ...objFields,
355→          ...extraFields,
356→          ...(cachedName ? { name: cachedName } : {}),
357→          ...(entry.position ? { position: entry.position } : {}),
358→          rawFields: new Map(entry.fields),
359→        } as any);
360→        if (!cachedName) {
361→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
362→        }
363→        break;
364→      }
365→      case "values": {
366→        const entity = conn.entityStore.get(entry.guid);
367→        if (!entity) break;
368→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
369→        let extraFields: Record<string, unknown> = {};
370→        if (
371→          entity.objectType === ObjectType.UNIT ||
372→          entity.objectType === ObjectType.PLAYER
373→        ) {
374→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
375→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
376→          extraFields = extractGameObjectFields(entry.fields);
377→        }
378→        const allChanged = [
379→          ...(objFields._changed || []),
380→          ...((extraFields as any)._changed || []),
381→        ];
382→        const merged: Record<string, unknown> = {};
383→        for (const key of allChanged) {
384→          if (key in extraFields) merged[key] = (extraFields as any)[key];
385→          else if (key in objFields) merged[key] = (objFields as any)[key];
386→        }
387→        conn.entityStore.update(entry.guid, merged);
388→        for (const [k, v] of entry.fields) {
389→          const existing = conn.entityStore.get(entry.guid);
390→          if (existing) existing.rawFields.set(k, v);
391→        }
392→        break;
393→      }
394→      case "movement": {
395→        conn.entityStore.setPosition(entry.guid, entry.position);
396→        break;
397→      }
398→      case "outOfRange": {
399→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
400→        break;
401→      }
402→      case "nearObjects": {
403→        break;
404→      }
405→    }
406→  }
407→}
