409→export function handleCompressedUpdateObject(
410→  conn: WorldConn,
411→  r: PacketReader,
412→): void {
413→  const uncompressedSize = r.uint32LE();
414→  const compressed = r.bytes(r.remaining);
415→  const decompressed = inflateSync(compressed);
416→  if (decompressed.length !== uncompressedSize) {
417→    throw new Error(
418→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
419→    );
420→  }
421→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
422→}
