447→export function queryEntityName(
448→  conn: WorldConn,
449→  guid: bigint,
450→  objectType: number,
451→  entry: number | undefined,
452→): void {
453→  if (objectType === ObjectType.PLAYER) {
454→    const guidLow = Number(guid & 0xffffffffn);
455→    const key = `player:${guidLow}`;
456→    if (conn.pendingNameQueries.has(key)) return;
457→    conn.pendingNameQueries.add(key);
458→    const w = new PacketWriter();
459→    w.uint64LE(guid);
