463→  if (entry === undefined) return;
464→  const key = `${objectType}:${entry}`;
465→  if (conn.pendingNameQueries.has(key)) return;
466→  conn.pendingNameQueries.add(key);
467→  if (objectType === ObjectType.UNIT) {
468→    sendPacket(
469→      conn,
