  BATTLEGROUND: 0x2c,
  BATTLEGROUND_LEADER: 0x2d,
  PARTY_LEADER: 0x33,
  ROLL: 0x100,
} as const;

export const PartyResult = {
  SUCCESS: 0x00,
  BAD_PLAYER_NAME: 0x01,
  TARGET_NOT_IN_GROUP: 0x02,

