  1→import { RingBuffer } from "lib/ring-buffer";
  2→import { parseCommand } from "ui/commands";
  3→import {
  4→  formatMessage,
  5→  formatMessageObj,
  6→  formatWhoResults,
  7→  formatWhoResultsJson,
  8→  formatGroupEvent,
  9→  formatEntityEvent,
 10→  formatEntityEventObj,
 11→  formatFriendList,
 12→  formatFriendListJson,
 13→  formatFriendEvent,
 14→  formatFriendEventObj,
 15→  formatIgnoreList,
 16→  formatIgnoreListJson,
 17→  formatIgnoreEvent,
 18→  formatIgnoreEventObj,
 19→} from "ui/format";
 20→import type { FriendEvent } from "wow/friend-store";
 21→import type { IgnoreEvent } from "wow/ignore-store";
 22→import { SessionLog, type LogEntry } from "lib/session-log";
 23→import type { WorldHandle, ChatMessage, GroupEvent } from "wow/client";
 24→import { ObjectType } from "wow/protocol/entity-fields";
 25→import type {
 26→  Entity,
 27→  UnitEntity,
 28→  GameObjectEntity,
 29→  EntityEvent,
 30→} from "wow/entity-store";
 31→
 32→export type EventEntry = { text: string | undefined; json: string };
 33→
 34→export type IpcSocket = {
 35→  write(data: string | Uint8Array): number;
 36→  end(): void;
 37→};
 38→
 39→export type IpcCommand =
 40→  | { type: "chat"; message: string }
 41→  | { type: "say"; message: string }
 42→  | { type: "yell"; message: string }
 43→  | { type: "guild"; message: string }
 44→  | { type: "party"; message: string }
 45→  | { type: "emote"; message: string }
 46→  | { type: "dnd"; message: string }
 47→  | { type: "afk"; message: string }
 48→  | { type: "whisper"; target: string; message: string }
 49→  | { type: "read" }
 50→  | { type: "read_json" }
 51→  | { type: "read_wait"; ms: number }
 52→  | { type: "read_wait_json"; ms: number }
 53→  | { type: "stop" }
 54→  | { type: "status" }
 55→  | { type: "who"; filter?: string }
 56→  | { type: "who_json"; filter?: string }
 57→  | { type: "invite"; target: string }
 58→  | { type: "kick"; target: string }
 59→  | { type: "leave" }
 60→  | { type: "leader"; target: string }
 61→  | { type: "accept" }
 62→  | { type: "decline" }
 63→  | { type: "nearby" }
 64→  | { type: "nearby_json" }
 65→  | { type: "friends" }
 66→  | { type: "friends_json" }
 67→  | { type: "add_friend"; target: string }
 68→  | { type: "del_friend"; target: string }
 69→  | { type: "ignored" }
 70→  | { type: "ignored_json" }
 71→  | { type: "add_ignore"; target: string }
 72→  | { type: "del_ignore"; target: string }
 73→  | { type: "roll"; min: number; max: number }
 74→  | { type: "unimplemented"; feature: string };
 75→
 76→export function parseIpcCommand(line: string): IpcCommand | undefined {
 77→  if (line.startsWith("/")) {
 78→    const parsed = parseCommand(line);
 79→    switch (parsed.type) {
 80→      case "say":
 81→      case "yell":
 82→      case "guild":
 83→      case "party":
 84→      case "emote":
 85→      case "dnd":
 86→      case "afk":
 87→        return parsed;
 88→      case "whisper":
 89→        return parsed;
 90→      case "who":
 91→        return parsed.target
 92→          ? { type: "who", filter: parsed.target }
 93→          : { type: "who" };
 94→      case "invite":
 95→      case "kick":
 96→      case "leave":
 97→      case "leader":
 98→      case "accept":
 99→      case "decline":
100→        return parsed;
101→      case "friends":
102→        return { type: "friends" };
103→      case "add-friend":
104→        return { type: "add_friend", target: parsed.target };
105→      case "remove-friend":
106→        return { type: "del_friend", target: parsed.target };
107→      case "ignored":
108→        return { type: "ignored" };
109→      case "add-ignore":
110→        return { type: "add_ignore", target: parsed.target };
111→      case "remove-ignore":
112→        return { type: "del_ignore", target: parsed.target };
113→      case "roll":
114→        return parsed;
115→      case "unimplemented":
116→        return parsed;
117→      default:
118→        return { type: "say", message: line };
119→    }
120→  }
121→
122→  const spaceIdx = line.indexOf(" ");
123→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
124→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
125→
126→  switch (verb) {
127→    case "SAY":
128→    case "YELL":
129→    case "GUILD":
130→    case "PARTY":
131→    case "EMOTE":
132→    case "DND":
133→    case "AFK":
134→      return {
135→        type: verb.toLowerCase() as
136→          | "say"
137→          | "yell"
138→          | "guild"
139→          | "party"
140→          | "emote"
141→          | "dnd"
142→          | "afk",
143→        message: rest,
144→      };
145→    case "WHISPER": {
146→      const targetEnd = rest.indexOf(" ");
147→      if (targetEnd === -1)
148→        return { type: "whisper", target: rest, message: "" };
149→      return {
150→        type: "whisper",
151→        target: rest.slice(0, targetEnd),
152→        message: rest.slice(targetEnd + 1),
153→      };
154→    }
155→    case "READ":
156→      return { type: "read" };
157→    case "READ_JSON":
158→      return { type: "read_json" };
159→    case "READ_WAIT": {
160→      const ms = parseInt(rest, 10);
161→      if (!Number.isFinite(ms) || ms < 0) return undefined;
162→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
163→    }
164→    case "READ_WAIT_JSON": {
165→      const ms = parseInt(rest, 10);
166→      if (!Number.isFinite(ms) || ms < 0) return undefined;
167→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
168→    }
169→    case "STOP":
170→      return { type: "stop" };
171→    case "STATUS":
172→      return { type: "status" };
173→    case "WHO":
174→      return rest ? { type: "who", filter: rest } : { type: "who" };
175→    case "WHO_JSON":
176→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
177→    case "INVITE":
178→      return rest ? { type: "invite", target: rest } : undefined;
179→    case "KICK":
180→      return rest ? { type: "kick", target: rest } : undefined;
181→    case "LEAVE":
182→      return { type: "leave" };
183→    case "LEADER":
184→      return rest ? { type: "leader", target: rest } : undefined;
185→    case "ACCEPT":
186→      return { type: "accept" };
187→    case "DECLINE":
188→      return { type: "decline" };
189→    case "NEARBY":
190→      return { type: "nearby" };
191→    case "NEARBY_JSON":
192→      return { type: "nearby_json" };
193→    case "FRIENDS":
194→      return { type: "friends" };
195→    case "FRIENDS_JSON":
196→      return { type: "friends_json" };
197→    case "ADD_FRIEND":
198→      return rest ? { type: "add_friend", target: rest } : undefined;
199→    case "DEL_FRIEND":
200→      return rest ? { type: "del_friend", target: rest } : undefined;
201→    case "IGNORED":
202→      return { type: "ignored" };
203→    case "IGNORED_JSON":
204→      return { type: "ignored_json" };
205→    case "ADD_IGNORE":
206→      return rest ? { type: "add_ignore", target: rest } : undefined;
207→    case "DEL_IGNORE":
208→      return rest ? { type: "del_ignore", target: rest } : undefined;
209→    case "JOIN":
210→      return { type: "unimplemented", feature: "Channel join/leave" };
211→    case "GINVITE":
212→    case "GKICK":
213→    case "GLEAVE":
214→    case "GPROMOTE":
215→      return { type: "unimplemented", feature: "Guild management" };
216→    case "MAIL":
217→      return { type: "unimplemented", feature: "Mail" };
218→    case "ROLL": {
219→      const parts = rest.split(" ").filter(Boolean);
220→      if (parts.length >= 2)
221→        return {
222→          type: "roll",
223→          min: parseInt(parts[0]!, 10),
224→          max: parseInt(parts[1]!, 10),
225→        };
226→      if (parts.length === 1)
227→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
228→      return { type: "roll", min: 1, max: 100 };
229→    }
230→    default:
231→      return line ? { type: "chat", message: line } : undefined;
232→  }
233→}
234→
235→export function writeLines(socket: IpcSocket, lines: string[]): void {
236→  for (const line of lines) socket.write(line + "\n");
237→  socket.write("\n");
238→}
239→
240→function drainText(events: RingBuffer<EventEntry>): string[] {
241→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
242→}
243→
244→function drainJson(events: RingBuffer<EventEntry>): string[] {
245→  return events.drain().map((e) => e.json);
246→}
247→
248→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
249→  return events
250→    .slice(from)
251→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
252→}
253→
254→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
255→  return events.slice(from).map((e) => e.json);
256→}
257→
258→export async function dispatchCommand(
259→  cmd: IpcCommand,
260→  handle: WorldHandle,
261→  events: RingBuffer<EventEntry>,
262→  socket: IpcSocket,
263→  cleanup: () => void,
264→): Promise<boolean> {
265→  switch (cmd.type) {
266→    case "chat": {
267→      handle.sendInCurrentMode(cmd.message);
268→      const mode = handle.getLastChatMode();
269→      const label =
270→        mode.type === "whisper"
271→          ? `WHISPER ${mode.target}`
272→          : mode.type === "channel"
273→            ? `CHANNEL ${mode.channel}`
274→            : mode.type.toUpperCase();
275→      writeLines(socket, [`OK ${label}`]);
276→      return false;
277→    }
278→    case "say":
279→      handle.sendSay(cmd.message);
280→      writeLines(socket, ["OK"]);
281→      return false;
282→    case "yell":
283→      handle.sendYell(cmd.message);
284→      writeLines(socket, ["OK"]);
285→      return false;
286→    case "guild":
287→      handle.sendGuild(cmd.message);
288→      writeLines(socket, ["OK"]);
289→      return false;
290→    case "party":
291→      handle.sendParty(cmd.message);
292→      writeLines(socket, ["OK"]);
293→      return false;
294→    case "emote":
295→      handle.sendEmote(cmd.message);
296→      writeLines(socket, ["OK"]);
297→      return false;
298→    case "dnd":
299→      handle.sendDnd(cmd.message);
300→      writeLines(socket, ["OK"]);
301→      return false;
302→    case "afk":
303→      handle.sendAfk(cmd.message);
304→      writeLines(socket, ["OK"]);
305→      return false;
306→    case "whisper":
307→      handle.sendWhisper(cmd.target, cmd.message);
308→      writeLines(socket, ["OK"]);
309→      return false;
310→    case "roll":
311→      handle.sendRoll(cmd.min, cmd.max);
312→      writeLines(socket, ["OK"]);
313→      return false;
314→    case "read":
315→      writeLines(socket, drainText(events));
316→      return false;
317→    case "read_json":
318→      writeLines(socket, drainJson(events));
319→      return false;
320→    case "read_wait": {
321→      const start = events.writePos;
322→      await new Promise<void>((resolve) => {
323→        setTimeout(() => {
324→          writeLines(socket, sliceText(events, start));
325→          resolve();
326→        }, cmd.ms);
327→      });
328→      return false;
329→    }
330→    case "read_wait_json": {
331→      const start = events.writePos;
332→      await new Promise<void>((resolve) => {
333→        setTimeout(() => {
334→          writeLines(socket, sliceJson(events, start));
335→          resolve();
336→        }, cmd.ms);
337→      });
338→      return false;
339→    }
340→    case "stop":
341→      writeLines(socket, ["OK"]);
342→      cleanup();
343→      return true;
344→    case "status":
345→      writeLines(socket, ["CONNECTED"]);
346→      return false;
347→    case "who": {
348→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
349→      writeLines(socket, formatWhoResults(results).split("\n"));
350→      return false;
351→    }
352→    case "who_json": {
353→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
354→      writeLines(socket, [formatWhoResultsJson(results)]);
355→      return false;
356→    }
357→    case "invite":
358→      handle.invite(cmd.target);
359→      writeLines(socket, ["OK"]);
360→      return false;
361→    case "kick":
362→      handle.uninvite(cmd.target);
363→      writeLines(socket, ["OK"]);
364→      return false;
365→    case "leave":
366→      handle.leaveGroup();
367→      writeLines(socket, ["OK"]);
368→      return false;
369→    case "leader":
370→      handle.setLeader(cmd.target);
371→      writeLines(socket, ["OK"]);
372→      return false;
373→    case "accept":
374→      handle.acceptInvite();
375→      writeLines(socket, ["OK"]);
376→      return false;
377→    case "decline":
378→      handle.declineInvite();
379→      writeLines(socket, ["OK"]);
380→      return false;
381→    case "nearby": {
382→      const entities = handle.getNearbyEntities();
383→      writeLines(socket, entities.map(formatNearbyLine));
384→      return false;
385→    }
386→    case "nearby_json": {
387→      const entities = handle.getNearbyEntities();
388→      writeLines(
389→        socket,
390→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
391→      );
392→      return false;
393→    }
394→    case "friends": {
395→      const friends = handle.getFriends();
396→      writeLines(socket, formatFriendList(friends).split("\n"));
397→      return false;
398→    }
399→    case "friends_json": {
400→      const friends = handle.getFriends();
401→      writeLines(socket, [formatFriendListJson(friends)]);
402→      return false;
403→    }
404→    case "add_friend":
405→      handle.addFriend(cmd.target);
406→      writeLines(socket, ["OK"]);
407→      return false;
408→    case "del_friend":
409→      handle.removeFriend(cmd.target);
410→      writeLines(socket, ["OK"]);
411→      return false;
412→    case "ignored": {
413→      const ignored = handle.getIgnored();
414→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
415→      return false;
416→    }
417→    case "ignored_json": {
418→      const ignored = handle.getIgnored();
419→      writeLines(socket, [formatIgnoreListJson(ignored)]);
420→      return false;
421→    }
422→    case "add_ignore":
423→      handle.addIgnore(cmd.target);
424→      writeLines(socket, ["OK"]);
425→      return false;
426→    case "del_ignore":
427→      handle.removeIgnore(cmd.target);
428→      writeLines(socket, ["OK"]);
429→      return false;
430→    case "unimplemented":
431→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
432→      return false;
433→  }
434→}
435→
436→function objectTypeName(type: ObjectType): string {
437→  switch (type) {
438→    case ObjectType.UNIT:
439→      return "NPC";
440→    case ObjectType.PLAYER:
441→      return "Player";
442→    default:
443→      return `type ${type}`;
444→  }
445→}
446→
447→function formatNearbyLine(entity: Entity): string {
448→  if (
449→    entity.objectType === ObjectType.UNIT ||
450→    entity.objectType === ObjectType.PLAYER
451→  ) {
452→    const unit = entity as UnitEntity;
453→    const name = entity.name ?? "Unknown";
454→    const kind = objectTypeName(entity.objectType);
455→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
456→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
457→    const pos = entity.position
458→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
459→      : "";
460→    return `${name} (${kind}${level}) ${hp}${pos}`;
461→  }
462→  if (entity.objectType === ObjectType.GAMEOBJECT) {
463→    const name = entity.name ?? "Unknown";
464→    const pos = entity.position
465→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
466→      : "";
467→    return `${name} (GameObject)${pos}`;
468→  }
469→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
470→}
471→
472→function objectTypeString(type: ObjectType): string {
473→  switch (type) {
474→    case ObjectType.UNIT:
475→      return "unit";
476→    case ObjectType.PLAYER:
477→      return "player";
478→    case ObjectType.GAMEOBJECT:
479→      return "gameobject";
480→    default:
481→      return "object";
482→  }
483→}
484→
485→function formatNearbyObj(entity: Entity): Record<string, unknown> {
486→  const obj: Record<string, unknown> = {
487→    guid: `0x${entity.guid.toString(16)}`,
488→    type: objectTypeString(entity.objectType),
489→    name: entity.name,
490→  };
491→  if (
492→    entity.objectType === ObjectType.UNIT ||
493→    entity.objectType === ObjectType.PLAYER
494→  ) {
495→    const unit = entity as UnitEntity;
496→    obj["level"] = unit.level;
497→    obj["health"] = unit.health;
498→    obj["maxHealth"] = unit.maxHealth;
499→  }
500→  if (entity.objectType === ObjectType.GAMEOBJECT) {
501→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
502→  }
503→  if (entity.position) {
504→    obj["x"] = entity.position.x;
505→    obj["y"] = entity.position.y;
506→    obj["z"] = entity.position.z;
507→  }
508→  return obj;
