  YOU_JOINED: 0x02,
  YOU_LEFT: 0x03,
  WRONG_PASSWORD: 0x04,
  NOT_MEMBER: 0x05,
  MUTED: 0x11,
  BANNED: 0x13,
  ALREADY_MEMBER: 0x17,
